import React, { useState } from 'react';
import './styles/App.css';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import SearchForm from './components/SearchForm';
import FlightList from './components/FlightList';
import Footer from './components/Footer';

function App() {
  const [flights, setFlights] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  // Mock flight data
  const mockFlights = [
    {
      id: 1,
      airline: 'Emirates',
      flightNumber: 'EK 501',
      departure: 'New York (JFK)',
      arrival: 'Dubai (DXB)',
      departureTime: '10:30 AM',
      arrivalTime: '07:45 AM',
      duration: '12h 15m',
      price: 850,
      stops: 0,
      logo: 'https://via.placeholder.com/50x50/4a90e2/ffffff?text=EK'
    },
    {
      id: 2,
      airline: 'Qatar Airways',
      flightNumber: 'QR 702',
      departure: 'New York (JFK)',
      arrival: 'Dubai (DXB)',
      departureTime: '11:45 PM',
      arrivalTime: '08:30 PM',
      duration: '13h 45m',
      price: 720,
      stops: 1,
      logo: 'https://via.placeholder.com/50x50/8e44ad/ffffff?text=QR'
    },
    {
      id: 3,
      airline: 'Etihad Airways',
      flightNumber: 'EY 100',
      departure: 'New York (JFK)',
      arrival: 'Dubai (DXB)',
      departureTime: '02:15 PM',
      arrivalTime: '10:30 AM',
      duration: '14h 15m',
      price: 680,
      stops: 1,
      logo: 'https://via.placeholder.com/50x50/f39c12/ffffff?text=EY'
    },
    {
      id: 4,
      airline: 'Delta Airlines',
      flightNumber: 'DL 50',
      departure: 'New York (JFK)',
      arrival: 'Dubai (DXB)',
      departureTime: '08:00 PM',
      arrivalTime: '07:15 PM',
      duration: '15h 15m',
      price: 620,
      stops: 2,
      logo: 'https://via.placeholder.com/50x50/e74c3c/ffffff?text=DL'
    }
  ];

  const handleSearch = (searchData) => {
    setLoading(true);
    setSearched(true);
    
    // Simulate API call
    setTimeout(() => {
      setFlights(mockFlights);
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="App">
      <Navbar />
      <Hero />
      <SearchForm onSearch={handleSearch} />
      
      <section className="flights-section">
        <div className="container">
          {searched && (
            <>
              {loading ? (
                <div className="loading-spinner">
                  <div className="spinner"></div>
                  <p>Searching for flights...</p>
                </div>
              ) : (
                <FlightList flights={flights} />
              )}
            </>
          )}
        </div>
      </section>
      
      <Footer />
    </div>
  );
}

export default App;
